class Solution:
    def popcountDepth(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        res = []
        for query in queries:
            if query[0] == 1:
                count = 0
                for i in range(query[1], query[2] + 1):
                    depth = self.popcountDepthHelper(nums[i])
                    if depth == query[3]:
                        count += 1
                res.append(count)
            elif query[0] == 2:
                nums[query[1]] = query[2]
        return res

    def popcountDepthHelper(self, x: int) -> int:
        depth = 0
        while x > 1:
            x = bin(x & (x - 1)).count('1')
            depth += 1
        return depth
